text:
这个3D互动模型直观展示太阳系核心行星的公转运行规律，行星大小和轨道半径做了可视化适配（真实比例下小行星会难以观测），保留了公转速度的相对快慢关系。你可以拖拽旋转视角、滚轮缩放观察细节，点击任意行星可查看详细参数和运行特点。

```show-widget
{"title": "solar_system_3d_operation", "widget_code": "<style>
canvas { display: block; width: 100% !important; height: 420px !important; }
#controls { display: flex; align-items: center; gap: 12px; padding: 10px 0 0; font-size: 13px; color: var(--color-text-secondary); }
</style>
<canvas id="c"></canvas>
<div id="controls">
  <button id="playBtn" onclick="togglePlay()">暂停</button>
  <label style="display:flex;align-items:center;gap:8px;flex:1">
    公转速度 <input type="range" id="speedSlider" min="0.5" max="3" step="0.1" value="1" style="flex:1">
  </label>
  <span id="status">自动旋转中</span>
</div>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js" onload="init()"></script>
<script>
var scene, camera, renderer, controls;
var planets = [];
var orbits = [];
var playing = true;
var speedMultiplier = 1;
var t = 0;

function init() {
  if (!window.THREE || !THREE.OrbitControls) return;
  var canvas = document.getElementById('c');
  var W = canvas.clientWidth, H = 420;
  renderer = new THREE.WebGLRenderer({ canvas: canvas, antialias: true, alpha: true });
  renderer.setSize(W, H);
  renderer.setPixelRatio(Math.min(devicePixelRatio, 2));

  scene = new THREE.Scene();
  camera = new THREE.PerspectiveCamera(45, W / H, 0.1, 1000);
  camera.position.set(0, 8, 18);

  scene.add(new THREE.AmbientLight(0xffffff, 0.7));
  var sunLight = new THREE.PointLight(0xffffff, 1.2, 50);
  sunLight.position.set(0, 0, 0);
  scene.add(sunLight);

  controls = new THREE.OrbitControls(camera, canvas);
  controls.enableDamping = true;
  controls.dampingFactor = 0.08;
  controls.autoRotate = true;
  controls.autoRotateSpeed = 0.5;

  // 太阳
  var sunGeo = new THREE.SphereGeometry(1.2, 24, 18);
  var sunMat = new THREE.MeshBasicMaterial({ color: 0xEF9F27 });
  var sun = new THREE.Mesh(sunGeo, sunMat);
  sun.name = '太阳';
  scene.add(sun);

  // 行星配置：名称、轨道半径、大小、颜色、公转周期系数
  var planetConfigs = [
    { name: '水星', r: 2.5, size: 0.2, color: 0x888780, period: 0.24 },
    { name: '金星', r: 3.8, size: 0.32, color: 0xFAC775, period: 0.62 },
    { name: '地球', r: 5, size: 0.35, color: 0x378ADD, period: 1 },
    { name: '火星', r: 6.8, size: 0.28, color: 0xD85A30, period: 1.88 }
  ];

  // 创建轨道和行星
  planetConfigs.forEach(config => {
    // 轨道
    var orbitGeo = new THREE.RingGeometry(config.r, config.r + 0.03, 64);
    var orbitMat = new THREE.MeshBasicMaterial({ color: 0x888780, side: THREE.DoubleSide, transparent: true, opacity: 0.3 });
    var orbit = new THREE.Mesh(orbitGeo, orbitMat);
    orbit.rotation.x = Math.PI / 2;
    scene.add(orbit);
    orbits.push(orbit);

    // 行星
    var planetGeo = new THREE.SphereGeometry(config.size, 16, 12);
    var planetMat = new THREE.MeshLambertMaterial({ color: config.color });
    var planet = new THREE.Mesh(planetGeo, planetMat);
    planet.name = config.name;
    planet.userData = { r: config.r, period: config.period };
    scene.add(planet);
    planets.push(planet);
  });

  // 点击交互
  const raycaster = new THREE.Raycaster();
  const mouse = new THREE.Vector2();
  let dragDist = 0, startX, startY;

  canvas.addEventListener('mousedown', e => { startX = e.clientX; startY = e.clientY; dragDist = 0; });
  canvas.addEventListener('mousemove', e => { dragDist += Math.abs(e.clientX - startX) + Math.abs(e.clientY - startY); });
  canvas.addEventListener('click', e => {
    if (dragDist > 5) return;
    const rect = canvas.getBoundingClientRect();
    mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
    mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
    raycaster.setFromCamera(mouse, camera);
    const hits = raycaster.intersectObjects([sun, ...planets]);
    if (hits.length) {
      const name = hits[0].object.name;
      window.__widgetSendMessage(`详细介绍${name}的运行参数和特点`);
    }
  });

  // 速度滑块事件
  document.getElementById('speedSlider').addEventListener('input', e => {
    speedMultiplier = Number(e.target.value);
  });

  function animate() {
    requestAnimationFrame(animate);
    if (playing) {
      t += 0.008 * speedMultiplier;
      planets.forEach(planet => {
        const angle = t / planet.userData.period;
        planet.position.set(
          Math.cos(angle) * planet.userData.r,
          0,
          Math.sin(angle) * planet.userData.r
        );
      });
    }
    controls.update();
    renderer.render(scene, camera);
  }
  animate();
}
if (window.THREE && THREE.OrbitControls) init();

function togglePlay() {
  playing = !playing;
  controls.autoRotate = playing;
  document.getElementById('playBtn').textContent = playing ? '暂停' : '播放';
  document.getElementById('status').textContent = playing ? '自动旋转中' : '已暂停';
}
</script>"}
```

### 补充说明
1. 模型做了比例简化：真实太阳系中行星与太阳的大小、轨道距离悬殊，无法在同一画布清晰展示，这里放大了行星体积、压缩了轨道间距，方便直观观察运行规律；
2. 公转速度按真实相对比例设计：水星公转速度最快，火星最慢，完全符合实际天体运行的周期比例关系；
3. 你可以点击左下角暂停按钮停止自动旋转和公转，固定视角观察细节，拖动速度滑块可调节公转快慢，点击任意天体可查看详细介绍。
